const input = $input.first().json;
const body = input.body || input;
const message = body.message || body.edited_message || null;
const text = typeof message?.text === 'string' ? message.text.trim() : '';
const chatId = message?.chat?.id || null;

if (!text || !chatId) return [];

return [{
  json: {
    updateId: body.update_id,
    messageId: message.message_id,
    chatId,
    text
  }
}];

const text = String($json.text || '').trim();
const parts = text.split(/\s+/).filter(Boolean);
const name = (parts[0] || '').toLowerCase().replace(/@[\w_]+$/, '');
const arg = (parts[1] || '').toLowerCase();

const missingFilter = `test -f scripts/filter/index.js && node scripts/filter/index.js || printf '%s\n' '{"message":"Filter is not implemented yet: scripts/filter/index.js"}'`;
const missingAudit = `test -f scripts/audit/index.js && node scripts/audit/index.js --batch=15 || printf '%s\n' '{"message":"Audit is not implemented yet: scripts/audit/index.js"}'`;

let command;
if (name === '/parse') {
  if (arg === 'auto') command = 'node scripts/parser/index.js --auto';
  else if (/^\d+$/.test(arg)) command = `node scripts/parser/index.js --niche=${arg}`;
  else command = 'node scripts/parser/index.js --list';
} else if (name === '/status') command = 'node scripts/telegram/command.js status';
else if (name === '/niches') command = 'node scripts/telegram/command.js niches';
else if (name === '/pause') command = 'node scripts/telegram/command.js pause';
else if (name === '/resume') command = 'node scripts/telegram/command.js resume';
else if (name === '/history') command = 'node scripts/telegram/command.js history';
else if (name === '/logs') command = 'node scripts/telegram/command.js logs';
else if (name === '/calls') command = 'node scripts/telegram/command.js calls';
else if (name === '/filter') command = missingFilter;
else if (name === '/run') command = missingAudit;
else command = 'node scripts/telegram/command.js help';

return [{ json: { command, chatId: $json.chatId, sourceText: text } }];

const input = $input.first().json;
let text = '';

if (typeof input.message === 'string') text = input.message;
else if (typeof input.error === 'string') text = `Error: ${input.error}`;
else if (typeof input.raw === 'string' && input.raw.trim()) text = input.raw;
else text = JSON.stringify(input, null, 2);

if (!text || !text.trim()) text = 'Done';
if (text.length > 3900) text = text.slice(0, 3900) + '\n...trimmed';

return [{ json: { chatId: $node['Route Command'].json.chatId, text } }];
